// Lenis
gsap.registerPlugin(ScrollTrigger);

  const lenis = new Lenis({
    lerp: 0.1,
    wheelMultiplier: 0.8,
    smoothWheel: true,
    smoothTouch: true
  });

  lenis.on('scroll', ScrollTrigger.update);

  gsap.ticker.add((time) => {
    lenis.raf(time * 1000);
  });

  gsap.ticker.lagSmoothing(0);

  ScrollTrigger.addEventListener("refresh", () => lenis.resize());
  ScrollTrigger.refresh();

function initDynamicCurrentYear() {  
  const currentYear = new Date().getFullYear();
  const currentYearElements = document.querySelectorAll('[data-current-year]');
  currentYearElements.forEach(currentYearElement => {
    currentYearElement.textContent = currentYear;
  });
}

// Initialize Dynamic Current Year
document.addEventListener('DOMContentLoaded', () => {
  initDynamicCurrentYear();
});

// Swiper
document.addEventListener("DOMContentLoaded", function () {
  
  document.querySelectorAll(".agenda-swiper").forEach(function (slider) {

    const swiperEl = slider.querySelector(".swiper");
    const nextBtn = slider.querySelector(".agenda-next");
    const prevBtn = slider.querySelector(".agenda-prev");

    new Swiper(swiperEl, {
      slidesPerView: 3.5,
      spaceBetween: 16,
      speed: 775,
      slidesOffsetAfter: 160,

      navigation: {
        nextEl: nextBtn,
        prevEl: prevBtn,
      },

      breakpoints: {
        0: { slidesPerView: 1.25, spaceBetween: 8, slidesOffsetAfter: 160 },
        768: { slidesPerView: 2.25, spaceBetween: 12, slidesOffsetAfter: 160 },
        1200: { slidesPerView: 2.5, spaceBetween: 16, slidesOffsetAfter: 160 },
        1440: { slidesPerView: 3.25, spaceBetween: 16, slidesOffsetAfter: 160 },
      },
    });

  });

});

// FAQ
document.addEventListener("click", (e) => {
  const trigger = e.target.closest(".faq_item_inner");
  if (!trigger) return;

  const item = trigger.closest(".faq_item");
  if (!item) return;

  const answer = item.querySelector(".faq_answer_wrapper");
  if (!answer) return;

  const isOpen = item.classList.contains("is-open");

  document.querySelectorAll(".faq_item.is-open").forEach((openItem) => {
    if (openItem === item) return;
    openItem.classList.remove("is-open");
    const openAnswer = openItem.querySelector(".faq_answer_wrapper");
    if (openAnswer) openAnswer.style.maxHeight = "0px";
  });

  if (isOpen) {
    item.classList.remove("is-open");
    answer.style.maxHeight = "0px";
  } else {
    item.classList.add("is-open");
    answer.style.maxHeight = answer.scrollHeight + "px";
  }
});

// Breadcrumbs
document.addEventListener("DOMContentLoaded", function () {
  const breadcrumb = document.querySelector('[data-breadcrumb="current"]');
  if (!breadcrumb) return;

  const pageTitle = document.title.split("•")[0].trim();
  breadcrumb.textContent = pageTitle;
});

// CMS Filters
document.addEventListener("DOMContentLoaded", () => {
  const filterEls = document.querySelectorAll("[data-filter]");
  const storyEls = document.querySelectorAll("[data-cats-source]");
  const modeEls = document.querySelectorAll("[data-filter-mode]");

  if (!filterEls.length || !storyEls.length) return;

  const normalize = (s) =>
    (s || "")
      .toString()
      .toLowerCase()
      .replace(/\s+/g, " ")
      .trim();

  const parseCats = (raw) =>
    (raw || "")
      .split(/,|•|\n|\r|\t/gi)
      .map(normalize)
      .filter(Boolean);

  const storyData = Array.from(storyEls).map((storyEl) => {
    const catsTextEl = storyEl.querySelector(".cats-text");
    const raw = catsTextEl ? catsTextEl.textContent : "";
    return { storyEl, cats: parseCats(raw) };
  });

  let selected = new Set();
  let mode = "or";

  const setActiveUI = () => {
    filterEls.forEach((el) => {
      const val = normalize(el.getAttribute("data-filter"));
      const isAlles = val === "alles";
      const isActive = isAlles ? selected.size === 0 : selected.has(val);
      el.classList.toggle("is-active", isActive);
    });

    modeEls.forEach((el) => {
      const m = normalize(el.getAttribute("data-filter-mode"));
      el.classList.toggle("is-active", m === mode);
    });
  };

  const matches = (cats) => {
    if (selected.size === 0) return true;
    const sel = Array.from(selected);
    if (mode === "and") return sel.every((s) => cats.includes(s));
    return sel.some((s) => cats.includes(s));
  };

  const render = () => {
    storyData.forEach(({ storyEl, cats }) => {
      storyEl.style.display = matches(cats) ? "" : "none";
    });
    setActiveUI();
  };

  const toggleFilter = (value) => {
    const v = normalize(value);
    if (v === "alles") {
      selected.clear();
      render();
      return;
    }
    if (selected.has(v)) selected.delete(v);
    else selected.add(v);
    render();
  };

  filterEls.forEach((el) => {
    el.addEventListener("click", (e) => {
      e.preventDefault();
      toggleFilter(el.getAttribute("data-filter"));
    });
  });

  modeEls.forEach((el) => {
    el.addEventListener("click", (e) => {
      e.preventDefault();
      const m = normalize(el.getAttribute("data-filter-mode"));
      if (m === "and" || m === "or") {
        mode = m;
        render();
      }
    });
  });

  render();
});
